        .replaceAll(' g ', ' g ')
        .replaceAll(' tan ', ' tangent ')
        .replaceAll(' cos ', ' cosine ')
        .replaceAll(' sin ', ' sine ');
  }

  Future<void> speak(String text) async {
    if (_useBackendTts) {
      try {
        final response = await http
